// CBOR fixture generator for SurrealDB.jl parity tests.
//
// Emits TOML `(label, hex)` pairs to stdout. Source of truth: ciborium
// 0.2.2 — the same crate the SurrealDB server uses on the wire.
//
// Regenerate:
//     cd test/fixtures/cbor/gen
//     cargo run > ../native.toml
//
// Map ordering: ciborium's Value::Map preserves Vec order. For canonical
// output (RFC 8949 §4.2.1), pairs are inserted in sorted-by-encoded-key
// order. Floats emit as f64 only (matches SurrealDB server behavior at
// convert.rs:373-374 — PublicNumber::Float → CborValue::Float (f64)).

use ciborium::value::{Integer, Value};

fn emit(label: &str, value: &Value) {
    let mut buf = Vec::new();
    ciborium::into_writer(value, &mut buf).expect("encode");
    // Quote the label — TOML treats unquoted dots as table nesting,
    // and our corpus uses dots (e.g. "float_1.1") and hyphens.
    println!("[\"{}\"]", label);
    println!("hex = \"{}\"", hex::encode(&buf));
    println!();
}

fn int(n: i128) -> Value {
    Value::Integer(Integer::try_from(n).expect("int range"))
}

fn array(items: Vec<Value>) -> Value {
    Value::Array(items)
}

fn map(mut pairs: Vec<(Value, Value)>) -> Value {
    // Sort keys to match server output: `convert.rs:651-660` emits maps
    // via BTreeMap<String,_> iteration (raw-string byte-lex). Mirroring
    // that here makes fixtures equal what the server actually emits, not
    // just what an unsorted-input ciborium call produces.
    pairs.sort_by(|a, b| {
        let key_bytes = |v: &Value| -> Vec<u8> {
            match v {
                Value::Text(s) => s.as_bytes().to_vec(),
                _ => {
                    let mut buf = Vec::new();
                    ciborium::into_writer(v, &mut buf).unwrap();
                    buf
                }
            }
        };
        key_bytes(&a.0).cmp(&key_bytes(&b.0))
    });
    Value::Map(pairs)
}

fn text(s: &str) -> Value {
    Value::Text(s.to_string())
}

fn main() {
    println!("# Generated by test/fixtures/cbor/gen — do not edit by hand.");
    println!("# Source of truth: ciborium 0.2.2 (SurrealDB server's CBOR crate).");
    println!("# Regenerate: cd test/fixtures/cbor/gen && cargo run > ../native.toml");
    println!();

    // === Unsigned integers — encoding-form coverage ===
    emit("uint_0", &int(0));
    emit("uint_1", &int(1));
    emit("uint_10", &int(10));
    emit("uint_23", &int(23));            // last immediate
    emit("uint_24", &int(24));            // first 1-byte
    emit("uint_25", &int(25));
    emit("uint_100", &int(100));
    emit("uint_255", &int(255));          // last 1-byte
    emit("uint_256", &int(256));          // first 2-byte
    emit("uint_1000", &int(1000));
    emit("uint_65535", &int(65535));      // last 2-byte
    emit("uint_65536", &int(65536));      // first 4-byte
    emit("uint_1_000_000", &int(1_000_000));
    emit("uint_u32max", &int(0xffff_ffff));
    emit("uint_2pow32", &int(0x1_0000_0000)); // first 8-byte
    emit("uint_1e12", &int(1_000_000_000_000));
    emit("uint_i64max", &int(i64::MAX as i128));
    emit("uint_u64max", &int(u64::MAX as i128));

    // === Negative integers ===
    emit("nint_-1", &int(-1));
    emit("nint_-10", &int(-10));
    emit("nint_-24", &int(-24));          // last immediate
    emit("nint_-25", &int(-25));          // first 1-byte
    emit("nint_-100", &int(-100));
    emit("nint_-1000", &int(-1000));
    emit("nint_i64min", &int(i64::MIN as i128));

    // === Floats (f64 only — server emits f64) ===
    emit("float_1.1", &Value::Float(1.1));
    emit("float_-4.1", &Value::Float(-4.1));
    emit("float_1e300", &Value::Float(1.0e+300));
    emit("float_0.0", &Value::Float(0.0));
    emit("float_-inf", &Value::Float(f64::NEG_INFINITY));
    emit("float_inf", &Value::Float(f64::INFINITY));
    // NaN payload bits are platform-defined; we check head + sign+exp
    // on the Julia side only, not full byte equality.

    // === Simple values / sentinels ===
    emit("bool_false", &Value::Bool(false));
    emit("bool_true", &Value::Bool(true));
    emit("null", &Value::Null);

    // === Text strings ===
    emit("text_empty", &text(""));
    emit("text_a", &text("a"));
    emit("text_ietf", &text("IETF"));
    emit("text_escape", &text("\"\\"));
    emit("text_u_umlaut", &text("ü"));    // 2-byte UTF-8
    emit("text_water", &text("水"));      // 3-byte UTF-8

    // === Byte strings ===
    emit("bytes_empty", &Value::Bytes(vec![]));
    emit("bytes_1234", &Value::Bytes(vec![0x01, 0x02, 0x03, 0x04]));

    // === Arrays ===
    emit("array_empty", &array(vec![]));
    emit("array_123", &array(vec![int(1), int(2), int(3)]));
    emit("array_nested",
         &array(vec![int(1), array(vec![int(2), int(3)]), array(vec![int(4), int(5)])]));
    // Length 25 → needs ai=24 form on the array head
    {
        let items: Vec<Value> = (1..=25).map(|n| int(n)).collect();
        emit("array_1_to_25", &array(items));
    }

    // === Maps (canonical key-sorted) ===
    emit("map_empty", &map(vec![]));
    // {1: 2, 3: 4} — keys already in canonical order
    emit("map_int_pairs", &map(vec![(int(1), int(2)), (int(3), int(4))]));
    // {"a": 1, "b": [2, 3]} — RFC §A canonical example
    emit("map_a1_b23", &map(vec![
        (text("a"), int(1)),
        (text("b"), array(vec![int(2), int(3)])),
    ]));
    // {"aa": 2, "b": 1} canonical-sorted: "b" (0x61, 0x62) < "aa" (0x62, 0x61, 0x61)
    emit("map_aa2_b1_sorted", &map(vec![
        (text("b"), int(1)),
        (text("aa"), int(2)),
    ]));

    // === Tags ===
    // L2 passthrough — unregistered tag for round-trip via Tagged wrapper
    emit("tag_passthrough_text",
         &Value::Tag(100, Box::new(text("x"))));

    // L3 typed: NONE = Tag(6, Null). Ref convert.rs:104,369
    emit("none", &Value::Tag(6, Box::new(Value::Null)));

    // L3 typed: Table = Tag(7, text). Ref convert.rs:188, 413-415
    emit("table_stream", &Value::Tag(7, Box::new(text("stream"))));

    // L3 typed: Decimal = Tag(10, text). Ref convert.rs:116-122, 375-377
    emit("decimal_pi", &Value::Tag(10, Box::new(text("3.14159265"))));
    emit("decimal_neg", &Value::Tag(10, Box::new(text("-0.5"))));

    // L3 typed: DateTime = Tag(12, [i64 secs, u32 nanos]). Server canonical.
    // Ref convert.rs:76-101 (decode), 395-405 (encode).
    let datetime = |secs: i64, nanos: u32| {
        Value::Tag(12, Box::new(array(vec![int(secs as i128), int(nanos as i128)])))
    };
    emit("datetime_epoch", &datetime(0, 0));
    emit("datetime_ns", &datetime(1_716_423_296, 123_456_789));

    // L3 typed: Duration = Tag(14, [] | [s] | [s, ns]). Compact form,
    // server canonical. Ref convert.rs:132-155 (decode), 380-393 (encode).
    let dur = |elems: Vec<Value>| Value::Tag(14, Box::new(array(elems)));
    emit("duration_zero", &dur(vec![]));
    emit("duration_1h",   &dur(vec![int(3600)]));
    emit("duration_1s500ms",
         &dur(vec![int(1), int(500_000_000)]));

    // L3 typed: File = Tag(55, [bucket, key]). Ref convert.rs:337-352, 437-443.
    emit("file_avatar",
         &Value::Tag(55, Box::new(array(vec![text("avatars"), text("user_42.png")]))));

    // L3 typed: Set = Tag(56, array). Elements sorted by encoded bytes
    // for deterministic output (matches our Julia encoder).
    emit("set_int_123",
         &Value::Tag(56, Box::new(array(vec![int(1), int(2), int(3)]))));
    emit("set_strings_abc",
         &Value::Tag(56, Box::new(array(vec![text("a"), text("b"), text("c")]))));

    // L3 typed: RecordID = Tag(8, [table_text, key]). Ref convert.rs:416-434
    // Key variants matching the polymorphic dispatch in convert.rs:586-599.
    let rid = |table: &str, key: Value| {
        Value::Tag(8, Box::new(array(vec![text(table), key])))
    };
    emit("recordid_int_key",
         &rid("users", int(42)));
    emit("recordid_string_key",
         &rid("users", text("alice")));
    emit("recordid_array_key",
         &rid("logs", array(vec![int(2026), int(5), int(22)])));
    emit("recordid_object_key",
         &rid("user", map(vec![
             (text("first"), text("ada")),
             (text("last"), text("lovelace")),
         ])));

    // L3 typed: UUID = Tag(37, 16 raw bytes big-endian).
    // Ref convert.rs:114 (decode), 407-409 (encode).
    let uuid = |bytes: Vec<u8>| {
        assert_eq!(bytes.len(), 16);
        Value::Tag(37, Box::new(Value::Bytes(bytes)))
    };
    let uuid_example_bytes: Vec<u8> = vec![
        0x12, 0x34, 0x56, 0x78, 0x12, 0x34, 0x56, 0x78,
        0x90, 0x12, 0x34, 0x56, 0x78, 0x90, 0x12, 0x34,
    ];
    emit("uuid_nil", &uuid(vec![0u8; 16]));
    emit("uuid_v4_example", &uuid(uuid_example_bytes.clone()));
    // RecordID with UUID key → Tag(8, [text, Tag(37, bytes)]).
    emit("recordid_uuid_key",
         &rid("users", uuid(uuid_example_bytes)));
}


